mapper.select:
/* com.erns.coching.favorite.mapper.FavoriteDAO.load */

SELECT

FROM T_FAVORITE_INF AA

	AND MEMB_SEQ 	= #{membSeq	, jdbcType=INTEGER}
	AND REF_CODE 	= #{refCode	, jdbcType=VARCHAR}
	AND REF_SEQ 	= #{refSeq	, jdbcType=INTEGER}

/* com.erns.coching.favorite.mapper.FavoriteDAO.getListVo */

SELECT

FROM T_FAVORITE_INF AA





	OFFSET #{offset} LIMIT #{rowSize}

/* com.erns.coching.favorite.mapper.FavoriteDAO.getList */
SELECT ZZ.* FROM ( SELECT
, RM.raw_seq , RM.raw_name , RDT.title , RDMI.memb_name AS MANAGER_NAME
FROM T_FAVORITE_INF AA
JOIN T_RAW_DETAIL RDT ON AA.ref_seq = RDT.raw_detail_seq JOIN T_RAW_MST RM ON RDT.raw_seq = RM.raw_seq JOIN T_MEMB_INF RDMI ON RDT.memb_seq = RDMI.memb_seq
ORDER BY AA.RGT_DTTM DESC
) ZZ
OFFSET #{offset} LIMIT #{rowSize}

/* com.erns.coching.favorite.mapper.FavoriteDAO.getListCount */
SELECT COUNT(*) FROM T_FAVORITE_INF AA
JOIN T_RAW_DETAIL RDT ON AA.ref_seq = RDT.raw_detail_seq JOIN T_RAW_MST RM ON RDT.raw_seq = RM.raw_seq JOIN T_MEMB_INF RDMI ON RDT.memb_seq = RDMI.memb_seq

